import React, { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import styles from "./Menu.module.css";

const Menu = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const [isOpen, setIsOpen] = useState(false); // Для модалки логина
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // Для бургер-меню
  const [mode, setMode] = useState("login");
  const [user, setUser] = useState(null);

  // Закрывать мобильное меню при переходе по ссылке
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [location]);

  // Остальная логика (useEffect для юзера, handleLogin и т.д.) остается прежней...
  // ... (копируй логику из предыдущего ответа)

  return (
    <>
      <nav className={styles.menu}>
        <div className={styles.menuInner}>
          <div className={styles.logo}>
            <Link to="/">SkillMeet</Link>
          </div>

          {/* Кнопка Бургер (видна только на мобилках) */}
          <button 
            className={styles.burgerBtn} 
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            <span className={isMobileMenuOpen ? styles.burgerClose : ""}></span>
          </button>

          {/* Навигация с динамическим классом для мобилки */}
          <div className={`${styles.navWrapper} ${isMobileMenuOpen ? styles.navActive : ""}`}>
            <ul className={styles.menuList}>
              {items.map((item) => (
                <li key={item.name}>
                  <Link
                    to={item.path}
                    className={location.pathname === item.path ? styles.active : ""}
                  >
                    {item.name}
                  </Link>
                </li>
              ))}
            </ul>

            <div className={styles.authActions}>
              {!user ? (
                <button className={styles.loginBtn} onClick={() => { setIsOpen(true); setIsMobileMenuOpen(false); }}>
                  Увійти
                </button>
              ) : (
                <div className={styles.userBlock}>
                  <span className={styles.userEmail}>{user.email}</span>
                  <button className={styles.logoutBtn} onClick={logout}>Вийти</button>
                </div>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* МОДАЛКА ВХОДА/РЕГИСТРАЦИИ */}
      {isOpen && (
        <div className={styles.modalOverlay} onClick={() => setIsOpen(false)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h2>{mode === "login" ? "Вхід" : "Реєстрація"}</h2>

            <form onSubmit={handleSubmit}>
              <input
                type="email"
                placeholder="Email"
                required
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />
              <input
                type="password"
                placeholder="Пароль"
                required
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              />

              <button type="submit" className={styles.submitBtn}>
                {mode === "login" ? "Увійти" : "Створити акаунт"}
              </button>
            </form>

            <p className={styles.switchMode}>
              {mode === "login" ? "Немає акаунта?" : "Вже є акаунт?"}
              <span onClick={() => setMode(mode === "login" ? "register" : "login")}>
                {mode === "login" ? "Реєстрація" : "Увійти"}
              </span>
            </p>

            <button className={styles.closeBtn} onClick={() => setIsOpen(false)}>
              Закрити
            </button>
          </div>
        </div>
      )}

      {/* ОШИБКА */}
      {isErrorOpen && (
        <div className={styles.modalOverlay} onClick={() => setIsErrorOpen(false)}>
          <div className={`${styles.modal} styles.errorModal`} onClick={(e) => e.stopPropagation()}>
            <h2>Помилка ❌</h2>
            <p>{errorMessage}</p>
            <button className={styles.closeBtn} onClick={() => setIsErrorOpen(false)}>
              Зрозуміло
            </button>
          </div>
        </div>
      )}
    </>
  );
};

export default Menu;
